mapper.update:
UPDATE aiot_device
SET device_name=#{deviceName}, device_type=#{deviceType}, ip_address=#{ipAddress},
    mac_address=#{macAddress}, mqtt_topic=#{mqttTopic}, sensor_list=#{sensorList},
    remarks=#{remarks}
WHERE id=#{id}

mapper.select:
SELECT * FROM aiot_device WHERE 1=1

    AND (device_code LIKE CONCAT('%',#{keyword},'%') OR device_name LIKE CONCAT('%',#{keyword},'%'))


    AND device_type=#{deviceType}


    AND online_status=#{onlineStatus}

ORDER BY update_time DESC
